/* ==========================================
  1. 纯文本气泡的通用底座 (排除图片和SVG)
  ========================================== */
.message-line .chat-bubble:not(:has(svg)):not(:has(img)) {
   position: relative !important;
   width: fit-content;
   max-width: 70vw;
   overflow-wrap: break-word;
   word-break: break-all;

   /* 留出左右十字架的空间 */
   margin: 0px 20px 0px 20px !important;
   padding: 10px 0px 10px 0px !important;
   overflow: visible !important;

   /* 彻底清除系统原有的背景、滤镜和圆角 */
   background: none !important;
   box-shadow: none !important;
   filter: none !important;
   backdrop-filter: none !important;        
   -webkit-backdrop-filter: none !important;
   border-radius: 0 !important;

   /* 边框图片拉伸的基础参数 */
   border-style: solid !important;
   border-color: transparent !important;
   border-image-slice: 30% 35% 30% 35% fill !important;
   border-image-repeat: stretch !important;
   border-image-width: 30px !important;
   border-image-outset: 12px !important;
}

/* ==========================================
  2. 发送方 (Sent / 右侧) 专属样式
  ========================================== */
/* 发送方气泡：黑底图，白字 */
.message-line.sent .chat-bubble.sent:not(:has(svg)):not(:has(img)) {
   border-image-source: url('https://test.fukit.cn/autoupload/f/TuvxadKC6bYfg4t-L9SE09iO_OyvX7mIgxFBfDMDErs/20260116/ynUi/2032X2032/8622080082804A4FC474480B19484D13.png/webp') !important;
   color: white !important;
}

/* 发送方左侧装饰：黑色十字架 */
.message-line.sent .chat-bubble.sent:not(:has(svg)):not(:has(img))::before {

   color: black !important;      
   font-size: 12px !important;  
   font-weight: bold !important;
   position: absolute !important;
   left: -30px !important;      
   top: 50% !important;          
   transform: translateY(-50%) !important;
