/* 接收方左侧装饰：白色十字架 */
.message-line.received .chat-bubble.received:not(:has(svg)):not(:has(img))::before {

   color: white !important;      
   font-size: 12px !important;  
   font-weight: bold !important;
   position: absolute !important;
   left: -30px !important;      
   top: 50% !important;          
   transform: translateY(-50%) !important;
   z-index: 10 !important;
}

/* 接收方右侧装饰：白色十字架 */
.message-line.received .chat-bubble.received:not(:has(svg)):not(:has(img))::after {

   color: white !important;
   font-size: 12px !important;
   position: absolute !important;
   right: -30px !important;      
   top: 50% !important;
   transform: translateY(-50%) !important;
   z-index: 10 !important;
}

/* ==========================================
  4. 图片/表情包/转账的“免气泡”纯净处理
  ========================================== */
.message-line.sent .chat-bubble.sent:has(svg),
.message-line.sent .chat-bubble.sent:has(img),
.message-line.received .chat-bubble.received:has(svg),
.message-line.received .chat-bubble.received:has(img) {
   /* 彻底透明化并去除一切边框效果 */
   background: transparent !important;
   box-shadow: none !important;
   border: none !important;
   backdrop-filter: none !important;        
   -webkit-backdrop-filter: none !important;

   /* 去除多余的内边距和外边距，让图片原生态贴合 */
   padding: 0 !important;
   margin: 0 !important;
   overflow: visible !important;
}

